class Solution {
    public int minSwaps(String s) {
        int n = s.length();
        int open = 0, close = 0, res = 0;
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == '[') open++;
            else close++;
            if (close > open) {
                res++;
                open++;
                close--;
            }
        }
        return res;
    }
}
